function qimanwu() {
  let disc = [];
  let Html = java.ajax(`${source.key}/custom/search`);
  let doc = org.jsoup.Jsoup.parse(Html);
  let tag = doc.select(".groupList li a");
  Array.from(tag).forEach(a => {
    disc.push({
      title: a.text(),
      url: a.attr("href") +"/page/{{page}}",
      style: {
        layout_flexGrow: 1,
        layout_flexBasisPercent: 0.45
      }
    });
  });

  disc.push({
    title: "精品漫画",
    url: "/custom/boutique",
    style: {layout_flexBasisPercent: 1, layout_flexGrow: 0.45}
  });

  disc.push({
    title: "最近更新",
    url: "/custom/update",
    style: {layout_flexBasisPercent: 1, layout_flexGrow: 0.45}
  });

  disc.push({
    title: "热门推荐",
    url: "/custom/recom",
    style: {layout_flexBasisPercent: 1, layout_flexGrow: 0.45}
  });

   return JSON.stringify(disc);
}
